import{_ as r,C as i,o as n,c as t,ag as a,E as l,w as s,a as u}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"Hero y banner","description":"La foto principal y mensaje de bienvenida de tu página","frontmatter":{"title":"Hero y banner","description":"La foto principal y mensaje de bienvenida de tu página"},"headers":[],"relativePath":"studio/hero-y-banner.md","filePath":"studio/hero-y-banner.md"}'),c={name:"studio/hero-y-banner.md"};function d(p,e,m,h,b,f){const o=i("Tip");return n(),t("div",null,[e[1]||(e[1]=a('<p>El hero es lo primero que ve tu cliente cuando entra a tu página. Es tu oportunidad de causar una buena primera impresión.</p><h2 id="que-es-el-hero" tabindex="-1">Qué es el hero <a class="header-anchor" href="#que-es-el-hero" aria-label="Permalink to &quot;Qué es el hero&quot;">​</a></h2><p>Es la sección grande en la parte superior de tu página. Incluye:</p><ul><li>Una foto de fondo (tu local, tu producto estrella, o algo representativo)</li><li>El nombre de tu negocio</li><li>Tu slogan o descripción corta</li><li>Un botón que lleva directo a tu WhatsApp</li></ul><h2 id="como-cambiar-la-foto-del-hero" tabindex="-1">Cómo cambiar la foto del hero <a class="header-anchor" href="#como-cambiar-la-foto-del-hero" aria-label="Permalink to &quot;Cómo cambiar la foto del hero&quot;">​</a></h2><ol><li>Abre tu panel de administración</li><li>Ve a <strong>Cómo Se Ve</strong></li><li>En la sección <strong>Hero</strong> dale clic a la imagen actual</li><li>Elige una nueva foto</li><li>Se guarda automáticamente</li></ol><h2 id="consejos-para-una-buena-foto-de-hero" tabindex="-1">Consejos para una buena foto de hero <a class="header-anchor" href="#consejos-para-una-buena-foto-de-hero" aria-label="Permalink to &quot;Consejos para una buena foto de hero&quot;">​</a></h2><ul><li>Usa una foto horizontal (paisaje), no vertical</li><li>Que se vea tu local, tu producto estrella, o tu equipo</li><li>Buena iluminación — evita fotos oscuras o borrosas</li><li>Tamaño máximo 2MB</li></ul><h2 id="el-banner-superior-plan-crecimiento-y-vision" tabindex="-1">El banner superior (plan Crecimiento y Visión) <a class="header-anchor" href="#el-banner-superior-plan-crecimiento-y-vision" aria-label="Permalink to &quot;El banner superior (plan Crecimiento y Visión)&quot;">​</a></h2><p>Además del hero, puedes activar un banner en la parte más alta de la página para destacar una promoción o mensaje especial. Ejemplo: &quot;Descuento del 20% esta semana&quot;.</p><p>Para activarlo: <strong>Configuración → Banner superior → Activar → Escribe el mensaje → Guardar</strong>.</p>',11)),l(o,null,{default:s(()=>[...e[0]||(e[0]=[u(' El botón del hero dice "Escríbenos" por defecto y abre tu WhatsApp. Es el elemento que más clics recibe en toda la página — asegúrate de que tu número esté bien configurado. ',-1)])]),_:1}),e[2]||(e[2]=a('<h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/seccion-visual.html">Variantes visuales</a> — Cambia el estilo del hero (fullscreen, split, gradient)</li><li><a href="/studio/paletas-de-color.html">Paletas de color</a> — Los colores afectan cómo se ve el hero</li><li><a href="/shared/imagenes.html">Subir imágenes</a> — Formatos y tamaños aceptados</li></ul>',2))])}const v=r(c,[["render",d]]);export{g as __pageData,v as default};
